#include <cuda_runtime.h>
#include <sys/time.h>

// Helper macros and functions to replace OpenCL utilities
#define cuda_errChk(status, msg, exitOnErr) \
    do { \
        if (status != cudaSuccess) { \
            fprintf(stderr, "CUDA Error: %s %s\n", cudaGetErrorString(status), msg); \
            if (exitOnErr) exit(-1); \
        } \
    } while (0)

void* alloc(size_t size) {
    void* ptr = malloc(size);
    if (ptr == NULL) {
        perror("malloc");
        exit(-1);
    }
    return ptr;
}

// Timing helper
void tvsub(struct timeval *t1, struct timeval *t2, struct timeval *res) {
    res->tv_sec = t1->tv_sec - t2->tv_sec;
    res->tv_usec = t1->tv_usec - t2->tv_usec;
    if (res->tv_usec < 0) {
        res->tv_sec--;
        res->tv_usec += 1000000;
    }
}

// CUDA kernels translated from OpenCL
__global__ void Fan1(float *m_dev,
                     float *a_dev,
                     float *b_dev,
                     const int size,
                     const int t) {
    int globalId = threadIdx.x + blockIdx.x * blockDim.x;

    if (size - 1 - t > globalId) {
        int idx_m = size * (globalId + t + 1) + t;
        int idx_a_num = size * (globalId + t + 1) + t;
        int idx_a_den = size * t + t;
        m_dev[idx_m] = a_dev[idx_a_num] / a_dev[idx_a_den];
    }
}

__global__ void Fan2(float *m_dev,
                     float *a_dev,
                     float *b_dev,
                     const int size,
                     const int t) {
    int globalIdx = threadIdx.x + blockIdx.x * blockDim.x;
    int globalIdy = threadIdx.y + blockIdx.y * blockDim.y;

    if (globalIdx < size - 1 - t && globalIdy < size - t) {
        int idx_a_target = size * (globalIdx + 1 + t) + (globalIdy + t);
        int idx_m = size * (globalIdx + 1 + t) + t;
        int idx_a_src = size * t + (globalIdy + t);

        a_dev[idx_a_target] -= m_dev[idx_m] * a_dev[idx_a_src];

        if (0 == globalIdy) {
            b_dev[globalIdx + 1 + t] -= m_dev[idx_m] * b_dev[t];
        }
    }
}

// Host functions translated from the logic in Source File 2 and 4
void InitMat(FILE *fp, int size, float *ary, int nrow, int ncol) {
    int i, j;
    for (i = 0; i < nrow; i++) {
        for (j = 0; j < ncol; j++) {
            fscanf(fp, "%f", &ary[size * i + j]);
        }
    }
}

void InitAry(FILE *fp, float *ary, int ary_size) {
    int i;
    for (i = 0; i < ary_size; i++) {
        fscanf(fp, "%f", &ary[i]);
    }
}

void PrintMat(float *ary, int size, int nrow, int ncol) {
    int i, j;
    for (i = 0; i < nrow; i++) {
        for (j = 0; j < ncol; j++) {
            printf("%8.2f ", ary[size * i + j]);
        }
        printf("\n");
    }
    printf("\n");
}

void PrintAry(float *ary, int ary_size) {
    int i;
    for (i = 0; i < ary_size; i++) {
        printf("%.2f ", ary[i]);
    }
    printf("\n");
}

void InitPerRun(int size, float *m) {
    int i;
    for (i = 0; i < size * size; i++) {
        m[i] = 0.0;
    }
}

void BackSub(float *a, float *b, float *finalVec, int size) {
    int i, j;
    for (i = 0; i < size; i++) {
        finalVec[size - i - 1] = b[size - i - 1];
        for (j = 0; j < i; j++) {
            finalVec[size - i - 1] -= a[size * (size - i - 1) + (size - j - 1)] * finalVec[size - j - 1];
        }
        finalVec[size - i - 1] = finalVec[size - i - 1] / a[size * (size - i - 1) + (size - i - 1)];
    }
}

void create_matrix(float *m, int size) {
    int i, j;
    float lamda = -0.01;
    float *coe = (float*)alloc(2 * size * sizeof(float));
    float coe_i = 0.0;

    for (i = 0; i < size; i++) {
        coe_i = 10 * exp(lamda * i);
        j = size - 1 + i;
        coe[j] = coe_i;
        j = size - 1 - i;
        coe[j] = coe_i;
    }

    for (i = 0; i < size; i++) {
        for (j = 0; j < size; j++) {
            m[i * size + j] = coe[size - 1 - i + j];
        }
    }
    free(coe);
}

int parseCommandline(int argc, char *argv[], char* filename,
                     int *q, int *v, int *t, int *p, int *d, int *size) {
    int i;
    if (2 > argc) return 1;
    char flag;

    for (i = 1; i < argc; i++) {
        if ('-' == argv[i][0]) {
            flag = argv[i][1];
            switch (flag) {
                case 's':
                    i++;
                    *size = atoi(argv[i]);
                    printf("Create matrix internally in parse, size = %d \n", *size);
                    break;
                case 'f':
                    i++;
                    strncpy(filename, argv[i], 100);
                    printf("Read file from %s \n", filename);
                    break;
                case 'h':
                    return 1;
                    break;
                case 'q':
                    *q = 1;
                    break;
                case 'v':
                    *v = 1;
                    break;
                case 't':
                    *t = 1;
                    break;
                case 'p':
                    i++;
                    *p = atoi(argv[i]);
                    break;
                case 'd':
                    i++;
                    *d = atoi(argv[i]);
                    break;
            }
        }
    }
    if ((*d >= 0 && 0 > *p) || (*p >= 0 && 0 > *d))
        return 1;
    return 0;
}

void printUsage() {
    printf("Gaussian Elimination Usage\n");
    printf("\n");
    printf("gaussianElimination [filename] [-hqt] [-p [int] -d [int]]\n");
    printf("\n");
    printf("example:\n");
    printf("$ ./gaussianElimination matrix4.txt\n");
    printf("\n");
    printf("filename     the filename that holds the matrix data\n");
    printf("\n");
    printf("-h           Display the help file\n");
    printf("-q           Quiet mode. Suppress all text output.\n");
    printf("-t           Print timing information.\n");
    printf("\n");
    printf("-p [int]     Choose the platform (must choose both platform and device)\n");
    printf("-d [int]     Choose the device (must choose both platform and device)\n");
    printf("\n");
    printf("\n");
    printf("Notes: 1. The filename is required as the first parameter.\n");
    printf("       2. If you declare either the device or the platform,\n");
    printf("          you must declare both.\n\n");
}

#ifdef TIMING
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_init_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;
#endif

void ForwardSub(float *a, float *b, float *m, int size, int timing) {
    float *a_dev, *b_dev, *m_dev;
    cudaError_t err;
    size_t mem_size_a = sizeof(float) * size * size;
    size_t mem_size_b = sizeof(float) * size;
    size_t mem_size_m = sizeof(float) * size * size;

    // Initialize CUDA device to ensure context is created
    err = cudaSetDevice(0);
    cuda_errChk(err, "Setting device", true);

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif

    // Allocate device memory
    err = cudaMalloc((void**)&a_dev, mem_size_a);
    cuda_errChk(err, "Allocating a_dev", true);
    err = cudaMalloc((void**)&b_dev, mem_size_b);
    cuda_errChk(err, "Allocating b_dev", true);
    err = cudaMalloc((void**)&m_dev, mem_size_m);
    cuda_errChk(err, "Allocating m_dev", true);

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
#endif

    // Copy data to device
#ifdef TIMING
    gettimeofday(&tv_h2d_start, NULL);
#endif
    err = cudaMemcpy(a_dev, a, mem_size_a, cudaMemcpyHostToDevice);
    cuda_errChk(err, "Copying a to device", true);
    err = cudaMemcpy(b_dev, b, mem_size_b, cudaMemcpyHostToDevice);
    cuda_errChk(err, "Copying b to device", true);
    err = cudaMemcpy(m_dev, m, mem_size_m, cudaMemcpyHostToDevice);
    cuda_errChk(err, "Copying m to device", true);
#ifdef TIMING
    gettimeofday(&tv_h2d_end, NULL);
    tvsub(&tv_h2d_end, &tv_h2d_start, &tv);
    h2d_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
#endif

    // Define block and grid sizes
    // Use smaller blocks to avoid resource exhaustion on some GPUs for large sizes
    dim3 block1(128);
    dim3 block2(16, 16);

    // Calculate grid sizes ensuring we cover the range
    int grid1_x = (size + block1.x - 1) / block1.x;
    int grid2_x = (size + block2.x - 1) / block2.x;
    int grid2_y = (size + block2.y - 1) / block2.y;

    int t;
    for (t = 0; t < size - 1; t++) {
        // Fan1
#ifdef TIMING
        gettimeofday(&tv_kernel_start, NULL);
#endif
        Fan1<<<grid1_x, block1>>>(m_dev, a_dev, b_dev, size, t);
        err = cudaGetLastError();
        cuda_errChk(err, "Executing Fan1", true);

        // Ensure completion before next iteration if dependencies exist (though here they are separate kernels)
        // But logically Fan2 depends on Fan1's output for the same 't'.
        err = cudaDeviceSynchronize();
        cuda_errChk(err, "Sync after Fan1", true);

#ifdef TIMING
        gettimeofday(&tv_kernel_end, NULL);
        tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
        kernel_time += tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
#endif

        // Fan2
#ifdef TIMING
        gettimeofday(&tv_kernel_start, NULL);
#endif
        dim3 grid2(grid2_x, grid2_y);
        Fan2<<<grid2, block2>>>(m_dev, a_dev, b_dev, size, t);
        err = cudaGetLastError();
        cuda_errChk(err, "Executing Fan2", true);

        err = cudaDeviceSynchronize();
        cuda_errChk(err, "Sync after Fan2", true);

#ifdef TIMING
        gettimeofday(&tv_kernel_end, NULL);
        tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
        kernel_time += tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
#endif
    }

    // Copy data back to host
#ifdef TIMING
    gettimeofday(&tv_d2h_start, NULL);
#endif
    err = cudaMemcpy(a, a_dev, mem_size_a, cudaMemcpyDeviceToHost);
    cuda_errChk(err, "Copying a to host", true);
    err = cudaMemcpy(b, b_dev, mem_size_b, cudaMemcpyDeviceToHost);
    cuda_errChk(err, "Copying b to host", true);
    err = cudaMemcpy(m, m_dev, mem_size_m, cudaMemcpyDeviceToHost);
    cuda_errChk(err, "Copying m to host", true);
#ifdef TIMING
    gettimeofday(&tv_d2h_end, NULL);
    tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
    d2h_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
#endif

    // Cleanup device memory
#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif
    cudaFree(a_dev);
    cudaFree(b_dev);
    cudaFree(m_dev);
#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time += tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
#endif
}

int main(int argc, char *argv[]) {
    float *a = NULL, *b = NULL, *finalVec = NULL;
    float *m = NULL;
    int size = -1;
    FILE *fp;
    char filename[200];
    int show_data = 0, quiet = 0, timing = 0, platform = 0, device = 0;

    if (parseCommandline(argc, argv, filename,
                         &quiet, &show_data, &timing, &platform, &device, &size)) {
        printUsage();
        return 0;
    }

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

    if (size < 1) {
        fp = fopen(filename, "r");
        if (!fp) {
            printf("Error opening file %s\n", filename);
            return -1;
        }
        fscanf(fp, "%d", &size);

        a = (float *)malloc(size * size * sizeof(float));
        InitMat(fp, size, a, size, size);

        b = (float *)malloc(size * sizeof(float));
        InitAry(fp, b, size);

        fclose(fp);
    } else {
        printf("create input internally before create, size = %d \n", size);
        a = (float *)malloc(size * size * sizeof(float));
        create_matrix(a, size);

        b = (float *)malloc(size * sizeof(float));
        for (int i = 0; i < size; i++)
            b[i] = 1.0;
    }

    if (!quiet && show_data) {
        printf("The input matrix a is:\n");
        PrintMat(a, size, size, size);

        printf("The input array b is:\n");
        PrintAry(b, size);
    }

    m = (float *)malloc(size * size * sizeof(float));
    finalVec = (float *)malloc(size * sizeof(float));

    InitPerRun(size, m);

    ForwardSub(a, b, m, size, timing);

    if (!quiet && show_data) {
        printf("The result of matrix m is: \n");
        PrintMat(m, size, size, size);
        printf("The result of matrix a is: \n");
        PrintMat(a, size, size, size);
        printf("The result of array b is: \n");
        PrintAry(b, size);

        BackSub(a, b, finalVec, size);
        printf("The final solution is: \n");
        PrintAry(finalVec, size);
    }

    free(m);
    free(a);
    free(b);
    free(finalVec);

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

    cudaDeviceReset();

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time += tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif

    return 0;
}
